import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider, useAuth } from './context/AuthContext';
import { NotificationProvider } from './context/NotificationContext';

import Navbar        from './components/layout/Navbar';
import Footer        from './components/layout/Footer';
import Home          from './pages/Home';
import Login         from './pages/Login';
import Register      from './pages/Register';
import PoojaCategories from './pages/PoojaCategories';
import PoojaList     from './pages/PoojaList';
import BookingFlow   from './pages/BookingFlow';
import PanditRegistration from './pages/PanditRegistration';
import PanditDashboard from './pages/PanditDashboard';
import PanditStatus from './pages/PanditStatus';
import AdminDashboard from './pages/AdminDashboard';
import Profile       from './pages/Profile';
import Festivals     from './pages/Festivals';
import Marketplace   from './pages/Marketplace';
import BookingSuccess from './pages/BookingSuccess';
import MyBookings    from './pages/MyBookings';
import TempleDirectory from './pages/TempleDirectory';
import LivestreamsPage from './pages/LivestreamsPage';
import UserLayout    from './components/layout/UserLayout';
import AIAssistant   from './pages/AIAssistant';
import PanchangPage  from './pages/PanchangPage';
import PaymentCallback from './pages/PaymentCallback';
import Notifications   from './pages/Notifications';

const ProtectedRoute = ({ children, roles }) => {
  const { user, isAuthenticated } = useAuth();
  if (!isAuthenticated) return <Navigate to="/login" replace />;
  if (roles && !roles.includes(user?.role)) return <Navigate to="/" replace />;
  return children;
};

const Layout = ({ children }) => (
  <div className="min-h-screen flex flex-col">
    <Navbar />
    <main className="flex-1">{children}</main>
    <Footer />
  </div>
);

// Simple placeholder for routes under construction
const ComingSoon = ({ title }) => (
  <div className="min-h-[60vh] flex flex-col items-center justify-center text-center px-4">
    <span className="text-5xl mb-4">🪔</span>
    <h1 className="text-2xl font-bold text-gray-800 font-serif mb-2">{title}</h1>
    <p className="text-gray-500">This feature is coming soon. Stay tuned!</p>
  </div>
);

const AppRoutes = () => {
  const { user } = useAuth();
  return (
  <NotificationProvider user={user}>
  <Routes>
    <Route path="/" element={<Layout><Home /></Layout>} />
    <Route path="/login"    element={<Login />} />
    <Route path="/register" element={<Register />} />
    <Route path="/poojas"   element={<Layout><PoojaCategories /></Layout>} />
    <Route path="/poojas/:categorySlug" element={<Layout><PoojaList /></Layout>} />
    <Route path="/book/:poojaSlug" element={
      <ProtectedRoute><Layout><BookingFlow /></Layout></ProtectedRoute>
    } />
    <Route path="/booking-success" element={
      <ProtectedRoute><Layout><BookingSuccess /></Layout></ProtectedRoute>
    } />
    <Route path="/my-bookings" element={
      <ProtectedRoute><UserLayout><MyBookings /></UserLayout></ProtectedRoute>
    } />
    <Route path="/my-orders" element={
      <ProtectedRoute><UserLayout><Marketplace ordersOnly /></UserLayout></ProtectedRoute>
    } />
    <Route path="/festivals"   element={<Layout><Festivals /></Layout>} />
    <Route path="/marketplace" element={<Layout><Marketplace /></Layout>} />
    <Route path="/profile"     element={
      <ProtectedRoute><UserLayout><Profile /></UserLayout></ProtectedRoute>
    } />
    <Route path="/temples" element={<Layout><TempleDirectory /></Layout>} />
    <Route path="/temples/livestreams" element={<Layout><ComingSoon title="Temple Livestreams" /></Layout>} />
    <Route path="/temples/details"     element={<Layout><ComingSoon title="Temple Details" /></Layout>} />
    <Route path="/temples/location"    element={<Layout><ComingSoon title="Temple Location" /></Layout>} />
    <Route path="/temples/info"        element={<Layout><ComingSoon title="Temple Information" /></Layout>} />
    <Route path="/livestreams" element={
      <ProtectedRoute><UserLayout><LivestreamsPage /></UserLayout></ProtectedRoute>
    } />
    <Route path="/panchang" element={<Layout><PanchangPage /></Layout>} />
    <Route path="/ai-assistant" element={
      <ProtectedRoute><UserLayout><AIAssistant /></UserLayout></ProtectedRoute>
    } />
    <Route path="/family"        element={<ProtectedRoute><UserLayout><ComingSoon title="Family Members" /></UserLayout></ProtectedRoute>} />
    <Route path="/kundli"        element={<ProtectedRoute><UserLayout><ComingSoon title="Kundli" /></UserLayout></ProtectedRoute>} />
    <Route path="/notifications" element={<ProtectedRoute><UserLayout><Notifications /></UserLayout></ProtectedRoute>} />
    <Route path="/settings"      element={<ProtectedRoute><UserLayout><ComingSoon title="Settings" /></UserLayout></ProtectedRoute>} />
    <Route path="/payment-callback/:merchantTransactionId" element={
      <ProtectedRoute><PaymentCallback /></ProtectedRoute>
    } />
    <Route path="/pandit/register" element={<Navigate to="/register" replace />} />
    <Route path="/pandit/dashboard" element={
      <ProtectedRoute roles={['pandit', 'admin']}><PanditDashboard /></ProtectedRoute>
    } />
    <Route path="/pandit/status" element={
      <ProtectedRoute roles={['pandit']}><PanditStatus /></ProtectedRoute>
    } />
    <Route path="/admin" element={
      <ProtectedRoute roles={['admin']}><AdminDashboard /></ProtectedRoute>
    } />
    <Route path="*" element={<Navigate to="/" replace />} />
  </Routes>
  </NotificationProvider>
  );
};

export default function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <Toaster position="top-right" toastOptions={{ duration: 3000 }} />
        <AppRoutes />
      </AuthProvider>
    </BrowserRouter>
  );
}
