import React, { useState, useRef, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import {
  Menu, X, User, LogOut, LayoutDashboard, BookOpen, ShoppingBag,
  Bell, Moon, Sparkles, Home, CalendarDays, MapPin, Tv,
  ChevronDown, Package, Users, Settings, Star,
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useNotifications } from '../../context/NotificationContext';

const PUBLIC_NAV = [
  { to: '/poojas',      label: 'Poojas'      },
  { to: '/festivals',   label: 'Festivals'   },
  { to: '/marketplace', label: 'Marketplace' },
  { to: '/temples',     label: 'Temples'     },
  { to: '/panchang',    label: 'Panchang'    },
];

const USER_NAV = [
  { to: '/',             label: 'Home',       icon: Home        },
  { to: '/poojas',       label: 'Poojas',     icon: Star        },
  { to: '/festivals',    label: 'Festivals',  icon: CalendarDays },
  { to: '/panchang',     label: 'Panchang',   icon: Moon        },
  { to: '/marketplace',  label: 'Shop',       icon: ShoppingBag },
  { to: '/livestreams',  label: 'Livestream', icon: Tv          },
  { to: '/ai-assistant', label: 'AI Guide',   icon: Sparkles    },
];

const TEMPLE_SUBMENU = [
  { to: '/temples',             label: 'Temple Directory'   },
  { to: '/temples/livestreams', label: 'Temple Livestreams' },
  { to: '/temples/details',     label: 'Temple Details'     },
  { to: '/temples/location',    label: 'Temple Location'    },
  { to: '/temples/info',        label: 'Temple Information' },
];

const PROFILE_MENU = [
  { to: '/profile',       label: 'My Profile',     icon: User    },
  { to: '/my-bookings',   label: 'My Bookings',    icon: BookOpen },
  { to: '/my-orders',     label: 'My Orders',      icon: Package  },
  { to: '/family',        label: 'Family Members', icon: Users    },
  { to: '/kundli',        label: 'Kundli',         icon: Star     },
  { to: '/notifications', label: 'Notifications',  icon: Bell     },
  { to: '/settings',      label: 'Settings',       icon: Settings },
];

function useClickOutside(ref, handler) {
  useEffect(() => {
    const listener = (e) => { if (ref.current && !ref.current.contains(e.target)) handler(); };
    document.addEventListener('mousedown', listener);
    return () => document.removeEventListener('mousedown', listener);
  }, [ref, handler]);
}

export default function Navbar() {
  const { user, isAuthenticated, logout } = useAuth();
  const { unreadCount } = useNotifications();
  const navigate  = useNavigate();
  const location  = useLocation();

  const [mobileOpen,  setMobileOpen]  = useState(false);
  const [profileOpen, setProfileOpen] = useState(false);
  const [templeOpen,  setTempleOpen]  = useState(false);
  const [scrolled,    setScrolled]    = useState(false);

  const profileRef = useRef(null);
  const templeRef  = useRef(null);

  useClickOutside(profileRef, () => setProfileOpen(false));
  useClickOutside(templeRef,  () => setTempleOpen(false));

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => { setMobileOpen(false); }, [location.pathname]);

  const handleLogout = () => { logout(); navigate('/'); setProfileOpen(false); setMobileOpen(false); };

  const isActive = (path) =>
    path === '/'
      ? location.pathname === '/'
      : location.pathname === path || location.pathname.startsWith(path + '/');

  const navLinkClass = (path) =>
    `relative px-3 py-2 font-medium text-sm transition-all duration-200 whitespace-nowrap font-sans group ${
      isActive(path) ? 'text-indigo-600' : 'text-gray-600 hover:text-indigo-600'
    }`;

  return (
    <>
      <nav
        className={`sticky top-0 z-50 transition-all duration-300 ${
          scrolled
            ? 'shadow-sm border-b border-gray-100/80'
            : 'border-b border-saffron-50/80'
        }`}
        style={scrolled
          ? { background: 'rgba(250,246,238,0.95)', backdropFilter: 'blur(24px) saturate(180%)', WebkitBackdropFilter: 'blur(24px) saturate(180%)' }
          : { background: 'rgba(250,246,238,0.85)', backdropFilter: 'blur(16px)', WebkitBackdropFilter: 'blur(16px)' }
        }
      >
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className={`flex items-center justify-between gap-4 transition-all duration-300 ${scrolled ? 'h-14' : 'h-16'}`}>

            {/* Logo */}
            <Link to="/" className="flex items-center gap-2 group shrink-0">
              <span className={`animate-float inline-block transition-all duration-300 ${scrolled ? 'text-xl' : 'text-2xl'}`}>🪔</span>
              <span className={`font-display font-bold text-maroon-700 group-hover:text-saffron-600 transition-all duration-300 ${scrolled ? 'text-xl' : 'text-2xl'}`}
                style={{ letterSpacing: '-0.02em' }}>
                Zutsav
              </span>
            </Link>

            {/* Desktop nav */}
            <div className="hidden lg:flex items-center gap-1 flex-1 justify-center">
              {isAuthenticated ? (
                <>
                  {USER_NAV.map((l) => (
                    <Link key={l.to} to={l.to} className={navLinkClass(l.to)}>
                      {l.label}
                      {/* Active underline indicator */}
                      <span className={`absolute bottom-0 left-3 right-3 h-0.5 rounded-full transition-all duration-200 ${isActive(l.to) ? 'opacity-100 scale-x-100' : 'opacity-0 scale-x-0'}`} style={{ background: '#D4AF37' }} />
                    </Link>
                  ))}

                  {/* Temples dropdown */}
                  <div className="relative" ref={templeRef}>
                    <button
                      onClick={() => setTempleOpen(!templeOpen)}
                      className={`relative flex items-center gap-1 px-3 py-2 font-medium text-sm transition-all duration-200 font-sans ${
                        location.pathname.startsWith('/temples') ? 'text-indigo-600' : 'text-gray-600 hover:text-indigo-600'
                      }`}
                    >
                      Temples
                      <ChevronDown size={13} className={`transition-transform duration-200 ${templeOpen ? 'rotate-180' : ''}`} />
                      {/* Active underline */}
                      <span className={`absolute bottom-0 left-3 right-3 h-0.5 rounded-full transition-all duration-200 ${location.pathname.startsWith('/temples') ? 'opacity-100 scale-x-100' : 'opacity-0 scale-x-0'}`} style={{ background: '#D4AF37' }} />
                    </button>
                    {templeOpen && (
                      <div className="absolute top-full left-0 mt-2 w-52 bg-white rounded-2xl shadow-luxury border border-gray-100 py-2 z-50 animate-scale-in">
                        {TEMPLE_SUBMENU.map((item) => (
                          <Link key={item.to} to={item.to} onClick={() => setTempleOpen(false)}
                            className="flex items-center gap-2.5 px-4 py-2.5 text-sm text-gray-600 hover:bg-saffron-50 hover:text-saffron-700 transition-colors font-sans">
                            <MapPin size={12} className="text-saffron-400 shrink-0" />
                            {item.label}
                          </Link>
                        ))}
                      </div>
                    )}
                  </div>
                </>
              ) : (
                PUBLIC_NAV.map((l) => (
                  <Link key={l.to} to={l.to} className={navLinkClass(l.to)}>
                    {l.label}
                    <span className={`absolute bottom-0 left-3 right-3 h-0.5 rounded-full transition-all duration-200 ${isActive(l.to) ? 'opacity-100 scale-x-100' : 'opacity-0 scale-x-0'}`} style={{ background: '#D4AF37' }} />
                  </Link>
                ))
              )}
            </div>

            {/* Auth area — desktop */}
            <div className="hidden lg:flex items-center gap-2 shrink-0">
              {isAuthenticated ? (
                <>
                  {/* Notification bell */}
                  <Link to="/notifications"
                    className="relative p-2 rounded-xl text-gray-500 hover:bg-saffron-50 hover:text-saffron-600 transition-colors">
                    <Bell size={19} />
                    {unreadCount > 0 && (
                      <span className="absolute -top-0.5 -right-0.5 min-w-[17px] h-[17px] bg-red-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center px-1 leading-none animate-pulse-soft font-sans">
                        {unreadCount > 99 ? '99+' : unreadCount}
                      </span>
                    )}
                  </Link>

                  {/* Profile dropdown */}
                  <div className="relative" ref={profileRef}>
                    <button
                      onClick={() => setProfileOpen(!profileOpen)}
                      className="flex items-center gap-2 pl-2 pr-3 py-1.5 rounded-xl hover:bg-saffron-50 transition-colors border border-transparent hover:border-saffron-100"
                    >
                      {user?.profilePhoto
                        ? <img src={`http://localhost:5000/${user.profilePhoto}`} alt="avatar"
                            className="w-8 h-8 rounded-full object-cover border-2 border-saffron-200 shrink-0" />
                        : <div className="w-8 h-8 rounded-full bg-gradient-to-br from-saffron-400 to-saffron-600 flex items-center justify-center shrink-0 shadow-sm">
                            <span className="text-white text-xs font-bold font-sans">{user?.name?.[0]?.toUpperCase()}</span>
                          </div>
                      }
                      <span className="text-sm font-medium text-gray-700 max-w-[80px] truncate font-sans">{user?.name?.split(' ')[0]}</span>
                      <ChevronDown size={13} className={`text-gray-400 transition-transform duration-200 ${profileOpen ? 'rotate-180' : ''}`} />
                    </button>

                    {profileOpen && (
                      <div className="absolute right-0 mt-2 w-60 bg-white rounded-2xl shadow-luxury border border-gray-100 py-2 z-50 animate-scale-in overflow-hidden">
                        {/* Profile header with gradient */}
                        <div className="px-4 py-3 mb-1"
                          style={{ background: 'linear-gradient(135deg, #fff8f0, #FAF6EE)' }}>
                          <div className="flex items-center gap-3">
                            {user?.profilePhoto
                              ? <img src={`http://localhost:5000/${user.profilePhoto}`} alt="avatar"
                                  className="w-10 h-10 rounded-full object-cover border-2 border-saffron-200 shrink-0" />
                              : <div className="w-10 h-10 rounded-full bg-gradient-to-br from-saffron-400 to-saffron-600 flex items-center justify-center shrink-0 shadow-sm">
                                  <span className="text-white text-sm font-bold font-sans">{user?.name?.[0]?.toUpperCase()}</span>
                                </div>
                            }
                            <div className="min-w-0">
                              <p className="font-semibold text-gray-900 text-sm truncate font-sans">{user?.name}</p>
                              <p className="text-xs text-saffron-600 capitalize font-medium font-sans">{user?.role}</p>
                            </div>
                          </div>
                        </div>

                        {PROFILE_MENU.map(({ to, label, icon: Icon }) => (
                          <Link key={to} to={to} onClick={() => setProfileOpen(false)}
                            className="flex items-center gap-3 px-4 py-2.5 text-sm text-gray-600 hover:bg-saffron-50 hover:text-saffron-700 transition-colors font-sans">
                            <Icon size={14} className="text-gray-400 shrink-0" />
                            <span className="flex-1">{label}</span>
                            {to === '/notifications' && unreadCount > 0 && (
                              <span className="bg-red-500 text-white text-[10px] font-bold min-w-[17px] h-[17px] rounded-full flex items-center justify-center px-1 font-sans">
                                {unreadCount > 99 ? '99+' : unreadCount}
                              </span>
                            )}
                          </Link>
                        ))}

                        {user?.role === 'pandit' && (
                          <Link to="/pandit/dashboard" onClick={() => setProfileOpen(false)}
                            className="flex items-center gap-3 px-4 py-2.5 text-sm text-gray-600 hover:bg-saffron-50 hover:text-saffron-700 transition-colors font-sans">
                            <LayoutDashboard size={14} className="text-gray-400" /> Pandit Dashboard
                          </Link>
                        )}
                        {user?.role === 'admin' && (
                          <Link to="/admin" onClick={() => setProfileOpen(false)}
                            className="flex items-center gap-3 px-4 py-2.5 text-sm text-gray-600 hover:bg-saffron-50 hover:text-saffron-700 transition-colors font-sans">
                            <LayoutDashboard size={14} className="text-gray-400" /> Admin Panel
                          </Link>
                        )}

                        <div className="border-t border-gray-100 mt-1 pt-1">
                          <button onClick={handleLogout}
                            className="w-full flex items-center gap-3 px-4 py-2.5 text-sm text-red-500 hover:bg-red-50 transition-colors font-sans">
                            <LogOut size={14} /> Sign Out
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                </>
              ) : (
                <>
                  <Link to="/login" className="btn-ghost text-sm font-sans">Login</Link>
                  <Link to="/register" className="btn-primary text-sm py-2 px-5 font-sans">Get Started</Link>
                </>
              )}
            </div>

            {/* Mobile hamburger */}
            <button
              className="lg:hidden p-2 rounded-xl text-gray-600 hover:bg-saffron-50 transition-colors shrink-0"
              onClick={() => setMobileOpen(!mobileOpen)}
            >
              {mobileOpen ? <X size={22} /> : <Menu size={22} />}
            </button>
          </div>
        </div>
      </nav>

      {/* ── Mobile drawer backdrop ─────────────────────────────────────── */}
      <div
        className={`lg:hidden fixed inset-0 bg-black/40 z-40 transition-opacity duration-300 ${mobileOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}
        onClick={() => setMobileOpen(false)}
      />

      {/* ── Mobile drawer panel ────────────────────────────────────────── */}
      <div
        className={`lg:hidden fixed top-0 left-0 h-full w-72 z-50 shadow-2xl flex flex-col transition-transform duration-300 ease-[cubic-bezier(0.32,0.72,0,1)] ${mobileOpen ? 'translate-x-0' : '-translate-x-full'}`}
        style={{ background: '#FAF6EE' }}
      >
        {/* Drawer header */}
        <div className="flex items-center justify-between px-5 py-4 border-b border-saffron-100">
          <Link to="/" className="flex items-center gap-2">
            <span className="text-xl">🪔</span>
            <span className="font-display text-xl font-bold text-maroon-700" style={{ letterSpacing: '-0.02em' }}>Zutsav</span>
          </Link>
          <button onClick={() => setMobileOpen(false)} className="p-1.5 rounded-xl text-gray-400 hover:bg-white/60 transition-colors">
            <X size={18} />
          </button>
        </div>

        {/* Drawer body */}
        <div className="flex-1 overflow-y-auto py-4 px-3 space-y-0.5">
          {isAuthenticated ? (
            <>
              {/* User info */}
              <div className="flex items-center gap-3 px-3 py-3 rounded-2xl mb-3"
                style={{ background: 'linear-gradient(135deg, #fff0d9, #fff8f0)' }}>
                {user?.profilePhoto
                  ? <img src={`http://localhost:5000/${user.profilePhoto}`} alt="avatar"
                      className="w-10 h-10 rounded-full object-cover border-2 border-saffron-200 shrink-0" />
                  : <div className="w-10 h-10 rounded-full bg-gradient-to-br from-saffron-400 to-saffron-600 flex items-center justify-center shrink-0 shadow-sm">
                      <span className="text-white text-sm font-bold font-sans">{user?.name?.[0]?.toUpperCase()}</span>
                    </div>
                }
                <div className="min-w-0">
                  <p className="font-semibold text-gray-800 text-sm truncate font-sans">{user?.name}</p>
                  <p className="text-xs text-saffron-600 capitalize font-medium font-sans">{user?.role}</p>
                </div>
              </div>

              <p className="px-3 py-1.5 text-[10px] font-bold text-gray-400 uppercase tracking-widest font-sans">Navigation</p>
              {USER_NAV.map(({ to, label, icon: Icon }) => (
                <Link key={to} to={to}
                  className={`flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-medium transition-colors font-sans ${
                    isActive(to) ? 'bg-saffron-100 text-saffron-700' : 'text-gray-700 hover:bg-white/70'
                  }`}>
                  <Icon size={16} className={isActive(to) ? 'text-saffron-500' : 'text-gray-400'} />
                  {label}
                </Link>
              ))}

              <p className="px-3 py-1.5 text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-2 font-sans">Temples</p>
              {TEMPLE_SUBMENU.slice(0, 2).map(({ to, label }) => (
                <Link key={to} to={to}
                  className="flex items-center gap-3 px-4 py-3 rounded-xl text-sm text-gray-700 hover:bg-white/70 transition-colors font-sans">
                  <MapPin size={16} className="text-gray-400" />
                  {label}
                </Link>
              ))}

              <p className="px-3 py-1.5 text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-2 font-sans">Account</p>
              {PROFILE_MENU.map(({ to, label, icon: Icon }) => (
                <Link key={to} to={to}
                  className="flex items-center gap-3 px-4 py-3 rounded-xl text-sm text-gray-700 hover:bg-white/70 transition-colors font-sans">
                  <Icon size={16} className="text-gray-400" />
                  <span className="flex-1">{label}</span>
                  {to === '/notifications' && unreadCount > 0 && (
                    <span className="bg-red-500 text-white text-[10px] font-bold min-w-[17px] h-[17px] rounded-full flex items-center justify-center px-1 font-sans">
                      {unreadCount > 99 ? '99+' : unreadCount}
                    </span>
                  )}
                </Link>
              ))}

              {user?.role === 'pandit' && (
                <Link to="/pandit/dashboard" className="flex items-center gap-3 px-4 py-3 rounded-xl text-sm text-gray-700 hover:bg-white/70 transition-colors font-sans">
                  <LayoutDashboard size={16} className="text-gray-400" /> Pandit Dashboard
                </Link>
              )}
              {user?.role === 'admin' && (
                <Link to="/admin" className="flex items-center gap-3 px-4 py-3 rounded-xl text-sm text-gray-700 hover:bg-white/70 transition-colors font-sans">
                  <LayoutDashboard size={16} className="text-gray-400" /> Admin Panel
                </Link>
              )}
            </>
          ) : (
            <>
              <p className="px-3 py-1.5 text-[10px] font-bold text-gray-400 uppercase tracking-widest font-sans">Menu</p>
              {PUBLIC_NAV.map(({ to, label }) => (
                <Link key={to} to={to}
                  className={`block px-4 py-3 rounded-xl text-sm font-medium transition-colors font-sans ${
                    isActive(to) ? 'bg-saffron-100 text-saffron-700' : 'text-gray-700 hover:bg-white/70'
                  }`}>
                  {label}
                </Link>
              ))}
            </>
          )}
        </div>

        {/* Drawer footer */}
        <div className="border-t border-saffron-100 p-4">
          {isAuthenticated ? (
            <button onClick={handleLogout}
              className="w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl text-sm text-red-500 hover:bg-red-50 transition-colors font-medium font-sans">
              <LogOut size={16} /> Sign Out
            </button>
          ) : (
            <div className="flex gap-2.5">
              <Link to="/login"    className="flex-1 btn-outline text-center text-sm py-2.5 font-sans">Login</Link>
              <Link to="/register" className="flex-1 btn-primary text-center text-sm py-2.5 font-sans">Get Started</Link>
            </div>
          )}
        </div>
      </div>
    </>
  );
}
