import React, { useEffect, useState } from 'react';
import { Bell, CheckCheck, Trash2, BookOpen, Package, Star, Users, ShoppingBag, AlertCircle } from 'lucide-react';
import { useNotifications } from '../context/NotificationContext';

const TYPE_CONFIG = {
  booking_created:   { icon: BookOpen,     color: 'bg-blue-100 text-blue-600',    label: 'Booking' },
  pandit_assigned:   { icon: Users,        color: 'bg-green-100 text-green-600',  label: 'Assignment' },
  new_booking:       { icon: BookOpen,     color: 'bg-saffron-100 text-saffron-600', label: 'New Booking' },
  booking_completed: { icon: CheckCheck,   color: 'bg-green-100 text-green-700',  label: 'Completed' },
  pandit_approved:   { icon: Star,         color: 'bg-gold-100 text-gold-700',    label: 'Approved' },
  pandit_registered: { icon: Users,        color: 'bg-purple-100 text-purple-600',label: 'Pandit' },
  user_registered:   { icon: Users,        color: 'bg-saffron-100 text-saffron-600', label: 'Welcome' },
  order_placed:      { icon: ShoppingBag,  color: 'bg-indigo-100 text-indigo-600',label: 'Order' },
  order_delivered:   { icon: Package,      color: 'bg-green-100 text-green-600',  label: 'Delivered' },
  otp_sent:          { icon: AlertCircle,  color: 'bg-yellow-100 text-yellow-700',label: 'OTP' },
};

function timeAgo(dateStr) {
  const diff = Date.now() - new Date(dateStr).getTime();
  const m = Math.floor(diff / 60000);
  if (m < 1)  return 'Just now';
  if (m < 60) return `${m}m ago`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h ago`;
  const d = Math.floor(h / 24);
  if (d < 7)  return `${d}d ago`;
  return new Date(dateStr).toLocaleDateString('en-IN');
}

export default function Notifications() {
  const {
    notifications, unreadCount, loading,
    fetchNotifications, markRead, markAllRead, deleteNotification, clearAll,
  } = useNotifications();

  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);

  useEffect(() => {
    fetchNotifications(1).then((data) => {
      setHasMore(data?.notifications?.length === 20);
      setPage(1);
    });
  }, []);

  const loadMore = async () => {
    const next = page + 1;
    const data = await fetchNotifications(next);
    if (data?.notifications?.length < 20) setHasMore(false);
    setPage(next);
  };

  return (
    <div className="max-w-2xl mx-auto space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div className="flex items-center gap-2">
          <Bell size={22} className="text-saffron-600" />
          <h1 className="text-2xl font-bold text-gray-800">Notifications</h1>
          {unreadCount > 0 && (
            <span className="bg-red-500 text-white text-xs font-bold px-2 py-0.5 rounded-full">
              {unreadCount} new
            </span>
          )}
        </div>
        <div className="flex gap-2">
          {unreadCount > 0 && (
            <button onClick={markAllRead}
              className="text-xs flex items-center gap-1 text-saffron-600 border border-saffron-300 px-3 py-1.5 rounded-lg hover:bg-saffron-50 transition-colors">
              <CheckCheck size={13} /> Mark all read
            </button>
          )}
          {notifications.length > 0 && (
            <button onClick={() => { if (window.confirm('Clear all notifications?')) clearAll(); }}
              className="text-xs flex items-center gap-1 text-red-500 border border-red-200 px-3 py-1.5 rounded-lg hover:bg-red-50 transition-colors">
              <Trash2 size={13} /> Clear all
            </button>
          )}
        </div>
      </div>

      {/* List */}
      {loading && notifications.length === 0 ? (
        <div className="space-y-3">
          {[1,2,3,4,5].map((i) => (
            <div key={i} className="bg-white rounded-2xl border border-gray-100 p-4 animate-pulse">
              <div className="flex gap-3">
                <div className="w-10 h-10 bg-gray-100 rounded-xl shrink-0" />
                <div className="flex-1 space-y-2">
                  <div className="h-3 bg-gray-100 rounded w-3/4" />
                  <div className="h-3 bg-gray-100 rounded w-1/2" />
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : notifications.length === 0 ? (
        <div className="text-center py-16 bg-white rounded-2xl border border-gray-100">
          <Bell size={40} className="text-gray-300 mx-auto mb-3" />
          <p className="text-gray-500 font-medium">No notifications yet</p>
          <p className="text-sm text-gray-400 mt-1">You'll see booking updates, order status, and more here.</p>
        </div>
      ) : (
        <div className="space-y-2">
          {notifications.map((n) => {
            const cfg  = TYPE_CONFIG[n.type] || { icon: Bell, color: 'bg-gray-100 text-gray-600', label: 'Info' };
            const Icon = cfg.icon;
            return (
              <div
                key={n._id}
                onClick={() => !n.isRead && markRead(n._id)}
                className={`group bg-white rounded-2xl border p-4 flex gap-3 items-start transition-all cursor-pointer hover:shadow-sm ${
                  n.isRead ? 'border-gray-100' : 'border-saffron-200 bg-saffron-50/30'
                }`}
              >
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 ${cfg.color}`}>
                  <Icon size={17} />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="flex items-start justify-between gap-2">
                    <div>
                      <p className={`text-sm font-semibold text-gray-800 ${!n.isRead ? 'font-bold' : ''}`}>{n.title}</p>
                      <p className="text-sm text-gray-600 mt-0.5 leading-snug">{n.message}</p>
                    </div>
                    <div className="flex items-center gap-2 shrink-0">
                      {!n.isRead && <span className="w-2 h-2 rounded-full bg-saffron-500 mt-1" />}
                      <button
                        onClick={(e) => { e.stopPropagation(); deleteNotification(n._id); }}
                        className="opacity-0 group-hover:opacity-100 text-gray-300 hover:text-red-500 transition-all p-0.5"
                      >
                        <Trash2 size={14} />
                      </button>
                    </div>
                  </div>
                  <p className="text-xs text-gray-400 mt-1.5">{timeAgo(n.createdAt)}</p>
                </div>
              </div>
            );
          })}

          {hasMore && (
            <button onClick={loadMore} disabled={loading}
              className="w-full text-sm text-saffron-600 py-3 border border-saffron-200 rounded-2xl hover:bg-saffron-50 transition-colors">
              {loading ? 'Loading...' : 'Load more'}
            </button>
          )}
        </div>
      )}
    </div>
  );
}
